  id: string;
  part?: string;
}

export interface BookTocPart {
  part: string;
  chapters: { title: string; id: string }[];
}
export type BookTocItem = BookTocPart | { title: string; id: string };

export interface BookData {
  title: string;
  slug: string;
  excerpt?: string;
  date: string;
  coverImage?: string;
  featured: boolean;
  draft: boolean;
  authors: string[];
  content: string;
  toc: BookTocItem[];
  chapters: BookChapterEntry[];
}

export interface BookChapterData {
  title: string;
  slug: string;
  bookSlug: string;
  content: string;
  headings: Heading[];
  excerpt?: string;
  latex: boolean;
  commentable?: boolean;
  readingTime: string;
  isFolder: boolean;
